module binary_decoder_2to4 (
    input wire [1:0] obf_in,
    output wire [3:0] out
);

    assign out = (obf_in == 2'b00) ? 4'b0001 :
                 (obf_in == 2'b01) ? 4'b0010 :
                 (obf_in == 2'b10) ? 4'b0100 :
                 (obf_in == 2'b11) ? 4'b1000 : 4'b0000;

endmodule
